insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2017-12-07','(Pedro)Se realiza escrito dirigido al Juzgado de Valencia de Alcántara en respuesta a su Diligencia de Ordenación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2017-12-07','Iciar: Llamo a Abraham - 927 23 47 06- para comunicarle la concesión de la pensión de viudedad a su madre y las cantidades que percibirá pero no contesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-12-07','(Pedro)Llamada de Mara (927-004349////74349), de la D. G. Infancia. +++Comunica que Dª Magdalena Carrasco Campañón, madre de D. Antonio (pareja de Dª Beatriz) y abuela de la pequeña Rocío, HA RECURRIDO el expediente de Protección de Menores. +++Envía por correo-e la Diligencia de Ordenación del Juzgado de 1ª Instancia e Instrucción nº 3 de Cáceres. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Mercedes, T. Soc. de Plena Inclusión de LLerena (924-871037). +++Enviará Informe de seguimiento. +++ADAPTACIÓN:buena,inicialmente se opone a las normas (protesta) pero luego las cumple. +++RELACIONES: MUY BUENA RELACIÓN TANTO CON EL PERSONAL DEL CENTRO COMO CON LOS COMPAÑEROS. +++HIJA: apenas la nombra en estos momentos. En la última conversación con Mª Ángeles (Psicóloga) comentó que para ella (Beatriz) era una de sus últimas preocupaciones. +++FAMILIA EXTENSA: Mercedes comenta que le dijo hace unos días, respecto a una conversscaión que había mantenido con su madre: "Mercedes, ¿yo puedo tener otra madre?...-¿por qué, le preguntó- Porque he habñlado con la mía y dice que no quiere saber nada de mí porque estoy en un centro..." +++++REcibe llamadas ocasionalmente. Con Antonio por wassapp. +++++Se presentaron en el centro hace unos días dos adultos con otro chico (de Apba.9 Villanueva de la Serena) que decía ser su novio. había quedado con Beatriz en hacer la visita pero ella no lo había dicho a las Educadoras: dada la situación le permitieron verla 10´ bajo supervisión (solo al chico). Al parecer, el chico le recriminaba que hubiera tenido un hijo con otro y que no le mandase mensajes de voz para escucharla. +++ANTICONCEPCIÓN: tiene ciat el lunes 11 de diciembre para analítica. Posteriormente la citarán para implante. Se recuerda epilepsia. +++SE propone que le hagan algun regalo para Reyes (MP3), lo cual ya tenían pensado. +++Cuidado con el móvil y las redes sociales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-11-24','NUEVA FECHA DE EXCARCELACIÓN: 25 DE ABRIL DE 2018.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-12-11','(Pedro). Hoy estaba prevista la reunión en el CSS de Mérida con Carmen Franco, Soraya y yo. +++Dado que la fecha de excarcelación prevista para el 25 de enero se ha aplazado (por otra causa pendiente) hasta el 25 de abril del 2018, Soraya considera que no es necesrio reunirse y tomar una decisión con tanto espacio de tiempo, ya que de lo que se trata es de que en el momento en el que salga Jesús haya plaz aen UME. +++SE aplaza pues esta reunión al mes de febrero, sin fijar fecha de momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2017-12-11','(Pedro)Llamada de D. Alexander Carteiro Trinidad (665-893265), marido de Dª Esperanza Vas Margullón, titular del contrato de alquiler de D. Pedro Sudón. +++Llama para informar de los desperfectos que hay en la voivienda. Esta dispuesto a devolver la fianza si nos hacemos cargo de los mismos, ya que su coste sobrepasa el de la fianza. +++Le pido que envíe fotografías de dichos desperfectos.Se le da el correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-12-11','CITACIÓN: Audiencia Provincial Sección nº 3 de Mérida. +++PROCEDIMIENTO: 0000042/2017 +++JUEVES, 14 DE DICIEMBRE, A LAS 9:30h. Sala de vistas nº 1.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2017-12-11','CIERRE EXPEDIENTE Se comprueba que Dña. Jacinta terminó formando parte de las tutelas de la CTAEx. Por ello, se procede al cierre del Expte. de Admón. de Bienes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA AMPARO'and edp.apellido1='MARTIN'and apellido2='ANGUITA'),'2017-12-12','ARCHIVO EXPEDIENTE Por parte del Jzdo. nº. 1, de Olivenza, se dictó Sentencia nº. 182/17, de 26/10, por la que se incapacitaba a Dña. Lucía Amparo. Se instituía la tutela y, para ejercer ésta, se nombra a su padre, D. Segundo Martín Díaz.***************Con f/ 01/12/2017, se solicita la confirmación de la susodicha Sentencia.*********************El 12/12/2017, se recibe DIOR indicando la firmeza definitiva de la Sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2017-12-12','Iciar: Hablo con Carmelo. Le indico que se le van a autorizar 250€ para el viaje que va a realizar a La Rioja en Navidad a visitar a su hermano José. Hemos confirmado con el hermano la visita.El reintegro lo podrá efectuar el 20/12','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2017-12-12','Se solicita intervención de la Policía Nacional para localizar el paradero de D. Rafael. Acudirá a la dirección que figura en su DNI, en Mérida, para saber si vive allí y nos comunicaran el resultado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamo al C. "Padre Cristóbal" (924-302618). Juan Antonio (T. Social). +++Rafael ha vuelto en alguna ocasión por el centro, habitualmente para "gestionar" alguna prestación del SEXPE. La última vez fue hace un par de semanas. +++Desconoce su paradero, aunque sabe que está en Mérida, cree que en una casa abandonada, pero no sabe dónde. +++La próxima vez que acuda al centro tratará de enterarse de su dirección, sin mencionar que la CTAEX está buscándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2017-12-13','-AMALIA: YA TENGO FIRMADO EL PIA ACTUAL : 300€ Y 20H DE SAD. HE CONTACTADO CON CERUJOVI QUE FUE QUIEN NOS HIZO EL ANTERIOR CONTRATO Y ME LO ENVIARÁN PARA QUE LO FIRMEMOS . LO HE SOLICITADO CON CLAUSULA SUSPENSIVA , EL SEPAD NOS COMUNICARÁ CUANDO EMPIEZAN A ABONAR Y SE LO COMUNICAREMOS A LA EMPRESA PARA EMPEZAR. CAMBIO LA DIRECCIÓN EN DEPENDENCIA PARA QUE NOS LLEGUE A NOSOTROS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2017-12-13','-ACEPTAMOS PIA ( PRESTACION EC PARA SAD ) . HABLO CON EL TECNICO PIA, LA MADRE VA A ELEGIR LA EMPRESA PQ TIENE UNA PERSONA QUE LE GUSTARIA Q FUESE LA AUXILIAR . ME ENVIARÁ EL CONTRATO PARA QUE LO FIRME. UNA VEZ Q TENGA CONTRATO + DOCUMENTACION PIA HAY QUE ENVIARLO A DEPENDENCIA MIAJADAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2017-12-13','(Pedro). Conversación con Ana Murillo. +++Se le envía autorización para que soliciten Informes Médicos con el fin de plantear revisón de discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-12-13','(Pedro).Conversación con Juan. +++"NO AGUANTO MÁS AQUÍ...Me quiero ir a un piso de alquiler en Zorita..." +++NO atiende a razones, no se considera enfermo, cree que es millonario... +++La próxima vez que vaya a Zorita buscará un piso de alquiler y nos enviará el presupuesto del mismo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Ángel)Conversación con Escalona. +++Expediente de ampliación de la incapacidad: Ref. Gabinete: 40387 +++Juzgado que lo atiende: Nº de 2 de Plasencia. Procedimiento 962/2016. +++Última comunicación con Gabinete: 01-09-2017: pendiente de exploración del médico forense. No hay nuevos contactos con el Juzgado desde enetonces.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2017-12-13','(Pedro)Conversación con Pilar Bueno (24146) +++Nos va a enviar una carta en la que solicita la tutelada conocer a su tutor. +++Cuando podamos acudiremos, pero de momento llmarla por teléfono. +++Propuesta de Pilar cuando hablemos con ella, decirle: "Si el psiquiatra te da el alta y tu familia te atiende no tenemos inconveninete en que te marches con ellos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2017-12-13','- LE PASO LLAVES A TONI FUTUEX PARA QUE COMPRUEBEN EL ESTADO DE LA VIVIENDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2017-12-14','- AMALIA: hablo con Rosa TS , la situacion de Bartó es de urgencia , se ha ido a vivir con él un señor conflictivo toxicomano que lleva los fines de semanas a sus nietos que son menores . Le explico que solo tenemos curatela ec. y sugiero que lo comunique a Fiscalia. Ya lo ha hecho con la intencion de que nos nombren tutores y podamos solicitarle plaza en Centro De Mayores. Futuex me comunica que ya no va a acompañarle al inyectable , desconociamos esto . De igual forma no es conveninte que hubiesen seguido en estas condiciones. Se lo comunico a Futuex la baja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2017-12-14','BIOPSIA "Buenas tardes: Nos notifican que el día 19/12/2017, las 8:00 horas de la mañana, vuelven a ingresar a Genaro para una nueva biopsia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2017-11-29','(Pedro). +++La Comisión Tutelar ha mantenido una reunión con los siguientes interlocutores: Alcalde y Delegada de Servicios Sociales, SSB y Programa de Familia de Villanueva del Fresno y Educadoras del CAM “Ana Bolaños”. +++Se mantuvo también una reunión con su Psiquiatra, el Dr.José Ramón Gutiérrez Casares, del Hospital Perpetuo Socorro de Badajoz. +++SE contactó con Futuex para que el día 5 de diciembre se le acompañara a retomar nuevamente el tratamiento, así como mantener dicho acompañamiento a las diferentes consultas en tanto en cuanto se determinara el recurso más idóneo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2017-12-04','(Pedro). mediante Nota Interior, se pone el caso en conocimiento de la Jefatura de Unidad de Programas Asistenciales, solcitando la convocatoria de una Subcomisión para valorar el caso y determinar el recurso más idóneo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-12-14','Iciar. HAblo con la Agencia TRibutaria de Zafra para saber si han enviado el cdo negativo que solicitamos. Dicen que ya fue enviado a C/ Toledillo de Jerez. Hablo con Silvia para que en su visita semanal a Ramón pregunte por la carta para facilitársela a Eugenia la T.S. En caso de que no la tenga Ramón lo volvería a solicitar por fax a la Agencia (Carmen 924 55 32 56)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-12-14','(Pedro). Comparecencia en la Audiencia Provincial, Sección 3, de Mérida. +++Pendiente de ejecución de sentencia: 4 años de medida de seguridad en CSS adecuado a su patología y el mismo periodo para la Orden de Alejamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2017-12-14','(Pedro) +++SE solcita en el Juzgado empoderamiento Apud-Acta para reclamación de deuda por impago de alquiler del local de Valencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2017-12-15','(Pedro)Intento de llamar a Maru, T. Soc. del C.Salud de Arroyo de la Luz (927 27 16 79). +++Solo está aquí los jueves. +++Resto de la semana en el C.S."Manuel Encinas" de Cáceres: +++++Teléfono directo: 52939 +++++927-249850/60/62 ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++hablo con Fátima, Médico de Familia de Eugenia en Arroyo de la Luz: +++Intentará hacer el Informe en la mañana de hoy y nos los enviará. Se deja fax y dos correos electrónicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-12-15','(Pedro)Conversación con Fernanda Gervás, T. Soc. SSB de Barcarrota (924-736026 y 650-661374). +++SE le indica que la curatela que tenemos con José Florencio es de carácter económico. +++SE le propone denucnciar ante la G. C. todos aquellos incidentes que sean susceptibles de ello así como informar al Juzgado en dicho sentido. +++Cuentan con la colaboración de la CTAEX para todo aquello que sea de nuestra competencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='LIRON'),'2017-12-15','(Pedro)Llamo a Mateo, T. Soc. de Torre de Santa María (hoy en Valdefuentes). +++OPINIÓN: "Nunca me ha dicho que se quiera ir de allí..." +++El próximo martes le hará una visita y remitirá un informe sobre esta situación, dada la petición de su hermano D. Luis para trasladarlo a la Residencia Real de Navalmoral.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN DIEGO'and edp.apellido1='BAUTISTA'and apellido2='GOMEZ'),'2017-12-13','Operación de testículo: orquiectomía reglada derecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN DIEGO'and edp.apellido1='BAUTISTA'and apellido2='GOMEZ'),'2017-12-15','Comunican Informe de Alta de fecha 14 de diciembre. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversdación con Ana Murillo, T. Soc. Plena Inclusion Cabeza del Buey (924-601081). +++Rubén pasó un poco intranquilo la noche tras la intervención (se quitó la vía), pero una vez dado el alta se encuentra tranquilo y bien. Están esperando que vaya el médico para saber si le pueden dar algún tranquilizante o analgésico, ya que en el Informe de Alta no dice nada al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2017-12-15','-AMALIA: ENVIO A LA SECCION DEPEDENCIA DE PLASENCIA LA ACEPTACION PIA CON LA PROPUESTA DE CENTRO RESIDENCIAL DE MAYORES. ADJUNTO AUTORIZACION JUDICIAL PARA EL MISMO YA CONCEDIDA. QUEDAMOS PENDIENTE PARA QUE SE NOS ADJUDIQUE PLAZA PUBLICA , ABIERTA A TODA LA CC.AA. PARA ACTIVAR EL 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2017-12-15','-AMALIA : JOSE A. SIGUE EN LA UDAC DE PLASENCIA. POR DEPENCIA LE HAN CONCEDIDO G.1 Y EL CADEX SIN EMBARGO LE DA EL PERFIL DE RAE . SE SOLIICTA PLAZA EN CENTRO DONDE EXISTA E.S.MENTAL CERCANO SEGÚN INDICACIONES CADEX . A LOS 45 DIAS DE INGRESAR EN EL CENTRO , TIENE QUE VOLVER A PASAR POR CADEX PARA VALORAR LA ADAPTACIÓN AL MISMO . QUEDO PTE. QUE SE ME INDIQUE PLAZA DISPONIBLE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2017-12-15','-AMALIA: HEMOS PODIDO CONFIRMAR FINALMENE QUE CARMEN PERCIBE DESDE 2003 LA PRESTACION A FAVOR DE FAMILIARES CON UNA CUANTIA DE 993´53€. CONSEGUIMOS A TRAVÉS DE FUTUEX COPIA DE SU DNI Y EL DE SUS PADRES. NO PROCEDE SOLICITAR OTRA PENSION.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-12-15','(Pedro)Conversación con José Antonio (en Casas de Don Antonio. 927-383194). +++Vanesa se marchó a finaes de noviembre de los pisos, volvió el 4 de diciembre: cogió el dinero y se volvió a ir. Regresó el 14 de diciembre (ayer), cogió los 20€ y se volvió a marchar. +++Planes de la madre de Vanesa: que se quede con ella en el piso alquilado que tiene minetras está trabajando cuidando a una señora mayor. +++++Si se termina el contrato, la madre volvería a Trujillo y la hija se quedaría en el piso, ayudándole a pagarlo. Y si se fuera con ella a Trujillo, podría vivir con la madre. +++++Si sucediese esto se podría contemplar un seguimineto domiciliario con Futuex. +++Riesgo: discusión con la madre y posible separación: en ese caso.De momento no dar de baja la plaza, hasta ver como queda la situación. +++José Antonio realizará informe con todas estas circunstancias y lo remitirá a la CTAEx. Una vez recibido, COMUNICAR la situación al JUZGADO +++se LE PROPONE también enviar dicho informe a la Unidad de recursos del SEPAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2017-12-18','- A PROPUESTA DEL SSB DE LA LOCALIDAD , SE HACE CAMBIO DE PIA , SOCILICITANDO PRESTACIÓN VINCULADA PARA CONTRATAR A LA ACTUAL AUXILAR PARA SAD. ADEMÁS TIENEN UN ENTORNO , UNA SOBRINA SE ENCARGA DE LOS CUIDADOS PERO LA SITUACIÓN ES DE CLAUDICACÍON EN BREVE.','2');
