insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2017-12-18','(Pedro) Conversación fcon Maru, T. Soc. C. Salud de Arroyo de la Luz. +++El Informe de Salud lo tiene que hacer Fátima, dado que es su Médico de familia. +++SE envía a Fátima, por correo-e modelo del Informe a realizar, dado que lo que nos ha enviado no es lo que se pidió. +++Contactaremos con ella la semana que viene (si no está todavía de permiso).','2');
