insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-12-18','(Pedro) Conversación con Carmen Barquilla, Fiscal de Cáceres (927-650273).En respuesta a la Providencia de 11 de diciembre de 2017. +++CORTE DE LUZ: no hay deudas pendientes, ni recibos impagados y los pàgos se están haciendo en la misma cuenta de la CAixa que siempre. +++DICE QUE NO TIENE PARA COMER: Carmen cree que le está pasando dinero a la mujer con la que convivió (y denunció) porque esta le está presionando. +++++Si lo está haciendo ha de ser de los 600€ que tiene asignados y, como Carmen comprender, la CTAEx no tiene medio alguno para controlar dicha situación si es que se está dando. Tampoco se puede descartar que sea un argucia de Ventura para conseguir más dinero...tengo mis dudas de que relamente no le llegue para comer. +++Pedimos, tras hablar con Carmen, a Futuex que trate de averiguar qué está pasando. +++++Cuando le han sacdo este tipo de temas se muestra muy reacio a hablar y muy opaco en sus respuestas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2017-12-18','(Pedro) Acudimos Teresa (Futuex) y yo a la vivienda de D. Ricardo (Teresa no la encontraba). +++NO HAY NINGÚN PROBLEMA DE HUMEDAD procedente del piso superior ni de ningún otro foco. +++Hay que pedir copia de la llave del portalón interior de la calle.','2');
