insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2017-12-18','(Pedro). Conversación con COPF Mérida. +++CITA PARA CONSULTA MAC: 20 de diciembre de 2017 a las 12:30h +++CITA PARA INSTAURAR MAC: 5 DE NERO A LAS 12:30. +++Se comunica a Javier Pecero dichas citas y pasarán a recoger el consentimiento informado y la autorización del la CTAEx el día 20 antes de ir al COPF.','2');
