insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2017-12-14','(Pedro). SE acude a Comisaría del CNP para plantear la búisqueda de D. rafael, en estos momentos en paradero desconoicido','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2017-12-18','(Pedro)Conversación con D. Cebrino, agente de la PN. +++Su compañero D. Jaime ha tratado de averiguar el paradero de D. Rafael acudiendo al "Padre Cristóbal" (hace tiempo que no acude por allí) así como al Padrón Municipal, donde no aparece ninguna dirección distinta a la que figura en el expediente. +++Se envía fax al Juzgado nº 4 de Badajoz informando de las indicaciones recibidas por parte de la Policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2017-12-18','(Pedro) Conversación con Mª José, hermana de Manuel. +++Durante el último mes: bebe alcohol, gasta todo su dinero. come en casa de mi hermana Isabel para no gastarse el dinero en comer -lo dice claramente- y después de comer se va de casa porque lo que QUIERE ES ESTAR SOLO. +++La relación con nostras se ha deteriorado de tal manera que ni mi hermana ni yo QEREMOS INTERVENIR EN NADA QUE TENGA QUE VER CON LA TUTELA DE MI HERMANO. VOSOTROS SOIS LOS TUTORES, HACED LO QUE TENGÁIS QUE HACER, PERO NO CONTÉIS CON NOSOTROS. ESO NO QUITA PARA QUE QUERAMOS SABER DE ÉL Y QUE SE ENCUENTRE BIEN..." +++eN LA RUPTURA DE LA REALCIÓN con las hermanos dice que ha influido úñltimamente la Auxiliar que trabaja con él en el CSS: su marido fue paciente mío en Mérida y a mi hermano le dice que soy una mala profesional. El viernes pasado llamé al chalet para decirle que ese viernes mi hermano iba a estar solo (yo estaba fuera y mi hermana no podía atenderle por ¿?). Al parecer la Auxiliar le dijo a mi hermano que yo no le quería dejar la llave y que iba a estar solo. +++NO ESTAMOS DE ACUERDO CON LA IDEA DE QUE SALGA DEL CSS al piso, que NO es suyo, sino de todos los hermanos (Yo le dije a mi madre que ese piso sería para mi hermano...).La casa sigue a nombre de mi madre. Hace dos semanas, había quedado con él para tom ar un café, pero me dpidió la llave del piso y, cuando le dije que no la llevaba encima, ME DEJÓ PLANTADA, diciendo "Va a tener que venir un juez paraq ue me des la llave.." y se marchó. +++"CON APOYO O SIN APOYO, MI HERMANO VA A ESTAR SOLO...PORQUE ES LO QUE QUIERE...SE METEÁ EN EL PISO A DEJAR PASAR EL TIEMPO, BEBIENDO CAFÉ ...QUE ES LO QUE HA HECHO DURANTE LOS ÚLTIMOS 15 AÑOS. pORQUE DELANTE DE VOSOTROS MUESTRA UNA CARA DE ESTABILIDAD, CORDIALIDAD Y ANTE NOSOTROS DA SU VERADERA CARA."','2');
